        String result = formatWithNullString.format(values);

        assertEquals("NULL,\"value\",NULL", result);
    }

    @Test
    public void testFormat_withEmptyValues_shouldReturnEmptyString() {
        Object[] values = new Object[] {};

        String result = csvFormat.format(values);

        assertEquals("", result);
    }

    @Test
    public void testFormat_whenIOExceptionThrown_shouldThrowIllegalStateException() throws Exception {
        // Create a mock CSVPrinter
        CSVPrinter mockPrinter = mock(CSVPrinter.class);
        // Disambiguate printRecord method by specifying varargs signature
        doThrow(new IOException("IO error")).when(mockPrinter).printRecord((Object[]) any());

        // Use reflection to replace the CSVPrinter constructor call inside CSVFormat.format method
        // Since CSVFormat is final and constructor is private, we cannot subclass or call constructor directly.
        // Instead, use reflection to inject a proxy CSVPrinter into CSVFormat.format via a helper.

        // Create a proxy CSVFormat to override format method to use mocked CSVPrinter
        CSVFormat proxyFormat = new CSVFormatProxy(csvFormat, mockPrinter);

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            proxyFormat.format("a");
        });

        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("IO error", thrown.getCause().getMessage());
    }

    private static class CSVFormatProxy extends CSVFormat {
        private final CSVFormat delegate;
        private final CSVPrinter printer;

        CSVFormatProxy(CSVFormat delegate, CSVPrinter printer) throws Exception {
            super(
                delegate.getDelimiter(),
                delegate.getQuoteChar(),
                delegate.getQuotePolicy(),
                delegate.getCommentStart(),
                delegate.getEscape(),
                delegate.getIgnoreSurroundingSpaces(),
                delegate.getIgnoreEmptyLines(),
                delegate.getRecordSeparator(),
                delegate.getNullString(),
                delegate.getHeader(),
                delegate.getSkipHeaderRecord()
            );
            this.delegate = delegate;
            this.printer = printer;
        }

        @Override
        public String format(final Object... values) {
            final StringWriter out = new StringWriter();
            try {
                // use the mocked printer which throws IOException
                printer.printRecord(values);
                return out.toString().trim();
            } catch (final IOException e) {
                throw new IllegalStateException(e);
            }
        }
    }

    @Test
    public void testFormat_withDifferentObjectTypes() {
        Object[] values = new Object[] {123, 45.67, true, 'x'};

        String result = csvFormat.format(values);

        assertEquals("\"123\",\"45.67\",\"true\",\"x\"", result);
    }

